#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char A[1005]; scanf("%s", A);
        int c0 = 0, c1 = 0;
        for (int i = 0; i < N; ++i) {
            if (A[i] == '0') c0++; else c1++;
        }
        char S[1005], Tstr[1005];
        int pos = 0;
        for (int i = 0; i < c0; ++i) S[pos++] = '0';
        for (int i = 0; i < c1; ++i) S[pos++] = '1';
        S[pos] = '\0';
        pos = 0;
        for (int i = 0; i < c1; ++i) Tstr[pos++] = '1';
        for (int i = 0; i < c0; ++i) Tstr[pos++] = '0';
        Tstr[pos] = '\0';
        printf("%s\n%s\n", S, Tstr);
    }
    return 0;
}

