code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String A = br.readLine().trim();
            int c0 = 0, c1 = 0;
            for (int i = 0; i < N; i++) {
                if (A.charAt(i) == '0') c0++; else c1++;
            }
            char[] sArr = new char[N];
            Arrays.fill(sArr, 0, c0, '0');
            Arrays.fill(sArr, c0, N, '1');
            char[] tArr = new char[N];
            Arrays.fill(tArr, 0, c1, '1');
            Arrays.fill(tArr, c1, N, '0');
            out.append(new String(sArr)).append('\n');
            out.append(new String(tArr)).append('\n');
        }
        System.out.print(out.toString());
    }
}

